import { Component, OnInit, isDevMode, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import { Invoice } from '../../models/invoice';
import { InvoiceCalcService, InvoiceTotals } from '../../services/invoice-calc.service';
import { InvoiceStoreService } from '../../services/invoice-store.service';
import { ElectronService } from '../../services/electron.service';

@Component({
  selector: 'app-invoice-preview',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './invoice-preview.component.html',
  styleUrls: ['./invoice-preview.component.css']
})
export class InvoicePreviewComponent implements OnInit {
  invoice: Invoice | null = null;

  totals: InvoiceTotals = {
    totalHT: 0,
    totalTVA: 0,
    totalTTC: 0,
    remise: 0,
    totalHTApresRemise: 0,
    totalTVAApresRemise: 0
  };

  logoAvailable = true;
  readonly isDev = isDevMode();

  debugUrl = '';
  debugId = '';
  debugCount = 0;
  marker = 'PREVIEW_COMPONENT_V5_' + Math.random().toString(16).slice(2);

  // ✅ TTC en lettres
  totalTtcWords = '';

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private store: InvoiceStoreService,
    public calc: InvoiceCalcService,
    public electron: ElectronService,
    private cdr: ChangeDetectorRef
  ) {}

  async ngOnInit(): Promise<void> {
    // valeurs immédiates
    this.debugUrl =
      (window.location.href || window.location.pathname || window.location.hash || '(no-url)') + '';
    this.debugId = '(loading...)';
    this.debugCount = -1;
    this.cdr.detectChanges();

    await this.store.load();

    // id: query param puis paramMap
    let id =
      this.route.snapshot.queryParamMap.get('id') ??
      this.route.snapshot.paramMap.get('id') ??
      this.route.snapshot.paramMap.get('invoiceId') ??
      '';

    // fallback: parse href
    const href = window.location.href || '';
    if (!id && href) {
      const m1 = href.match(/\/invoices\/([^\/?#]+)\/preview/i);
      if (m1?.[1]) id = m1[1];

      if (!id) {
        const m2 = href.match(/[?&]id=([^&]+)/i);
        if (m2?.[1]) id = decodeURIComponent(m2[1]);
      }
    }

    this.debugId = id || '(no-id)';
    this.debugCount = this.store.getSnapshot().length;

    if (this.isDev) {
      console.log('[InvoicePreview] LOADED', this.marker, {
        href,
        routerUrl: this.router.url,
        id: this.debugId,
        count: this.debugCount
      });
    }

    this.cdr.detectChanges();

    if (!id) {
      this.invoice = null;
      this.cdr.detectChanges();
      return;
    }

    const inv = await this.store.getById(id);
    this.invoice = inv;

    if (inv) {
      this.totals = this.calc.totals(inv);
      this.totalTtcWords = this.amountToWordsDT(this.totals.totalTTC);
    } else if (this.isDev) {
      console.warn('[InvoicePreview] invoice NOT FOUND for id:', id);
      this.totalTtcWords = '';
    }

    this.cdr.detectChanges();
  }

  back(): void {
    this.router.navigate(['/invoices']);
  }

  edit(): void {
    if (!this.invoice) return;
    this.router.navigate(['/invoices', this.invoice.id, 'edit']);
  }

  print(): void {
    window.print();
  }

  async exportPdf(): Promise<void> {
    if (!this.invoice) return;
    if (!this.electron.isElectron) return;

    try {
      const anyElectron: any = this.electron as any;

      if (typeof anyElectron.exportPdf === 'function') {
        await anyElectron.exportPdf();
        return;
      }

      if (anyElectron.ipcRenderer?.invoke) {
        await anyElectron.ipcRenderer.invoke('export-pdf');
        return;
      }

      alert('Export PDF non configuré dans ElectronService.');
    } catch (e) {
      console.error(e);
      alert('Erreur export PDF. Voir console.');
    }
  }

  // =========================
  // TTC en lettres (DT + millimes)
  // =========================
  private amountToWordsDT(amount: number): string {
    const safe = Number.isFinite(amount) ? amount : 0;

    const dinars = Math.floor(safe);
    const millimes = Math.round((safe - dinars) * 1000); // 1 DT = 1000 millimes

    const dinarsWords = this.numberToFrenchWords(dinars);
    const millimesWords = this.numberToFrenchWords(millimes);

    const dinarLabel = dinars <= 1 ? 'dinar' : 'dinars';
    const millimeLabel = millimes <= 1 ? 'millime' : 'millimes';

    return `${this.capitalize(dinarsWords)} ${dinarLabel} et ${millimesWords} ${millimeLabel}`;
  }

  private capitalize(text: string): string {
    if (!text) return text;
    return text.charAt(0).toUpperCase() + text.slice(1);
  }

  // Convertit 0..999999999 en lettres FR (suffisant pour factures)
  private numberToFrenchWords(n: number): string {
    n = Math.floor(Math.abs(n));
    if (n === 0) return 'zéro';

    const units = ['', 'un', 'deux', 'trois', 'quatre', 'cinq', 'six', 'sept', 'huit', 'neuf'];
    const teens = [
      'dix', 'onze', 'douze', 'treize', 'quatorze', 'quinze', 'seize',
      'dix-sept', 'dix-huit', 'dix-neuf'
    ];
    const tens = ['', '', 'vingt', 'trente', 'quarante', 'cinquante', 'soixante', 'soixante', 'quatre-vingt', 'quatre-vingt'];

    const underHundred = (x: number): string => {
      if (x < 10) return units[x];
      if (x < 20) return teens[x - 10];

      const t = Math.floor(x / 10);
      const u = x % 10;

      // 70-79 / 90-99
      if (t === 7 || t === 9) {
        const base = tens[t];
        const rest = x % 20; // 70..79 => 10..19, 90..99 => 10..19
        if (rest === 11) return `${base} et ${teens[1]}`; // soixante et onze
        return `${base}-${teens[rest - 10]}`;
      }

      // 80-89
      if (t === 8) {
        if (u === 0) return 'quatre-vingts';
        return `quatre-vingt-${units[u]}`;
      }

      if (u === 0) return tens[t];
      if (u === 1) return `${tens[t]} et un`;
      return `${tens[t]}-${units[u]}`;
    };

    const underThousand = (x: number): string => {
      const h = Math.floor(x / 100);
      const r = x % 100;

      if (h === 0) return underHundred(r);
      if (h === 1) return r === 0 ? 'cent' : `cent ${underHundred(r)}`;
      return r === 0 ? `${units[h]} cents` : `${units[h]} cent ${underHundred(r)}`;
    };

    const parts: string[] = [];

    const millions = Math.floor(n / 1_000_000);
    const thousands = Math.floor((n % 1_000_000) / 1000);
    const rest = n % 1000;

    if (millions > 0) {
      parts.push(millions === 1 ? 'un million' : `${this.numberToFrenchWords(millions)} millions`);
    }

    if (thousands > 0) {
      parts.push(thousands === 1 ? 'mille' : `${underThousand(thousands)} mille`);
    }

    if (rest > 0) {
      parts.push(underThousand(rest));
    }

    return parts.join(' ').replace(/\s+/g, ' ').trim();
  }
}
